parameters.jsonBody:
={
  "amount": {{ ($json.properties?.amount || 1000) * 100 }},
  "currency": "INR",
  "accept_partial": false,
  "description": "Payment for {{ $json.properties?.service_offered || 'Services' }} — {{ $json.properties?.dealname }}",
  "customer": {
    "name": "{{ $('Webhook — Deal Approved (Manual Trigger)').item.json.body.client_name }}",
    "email": "{{ $('Webhook — Deal Approved (Manual Trigger)').item.json.body.client_email }}",
    "contact": "{{ $('Webhook — Deal Approved (Manual Trigger)').item.json.body.client_phone || '' }}"
  },
  "notify": {"sms": true, "email": true},
  "reminder_enable": true,
  "expire_by": {{ Math.floor(Date.now()/1000) + 7*24*60*60 }},
  "notes": {
    "deal_id": "{{ $('Webhook — Deal Approved (Manual Trigger)').item.json.body.deal_id }}",
    "source": "ai-sales-automation"
  }
}

parameters.message:
=Hi {{ $('Webhook — Deal Approved (Manual Trigger)').item.json.body.client_name }},

Thank you for choosing to work with us! Here is your payment link:

{{ $('Razorpay — Create Payment Link').item.json.short_url }}

Amount: ₹{{ ($('HubSpot — Get Deal Details').item.json.properties.amount || 1000) }}
Service: {{ $('HubSpot — Get Deal Details').item.json.properties.service_offered || 'Services' }}

This link is valid for 7 days. If you have any questions, just reply to this email.

Best regards,
{{YOUR_NAME}}

